mapper.select:
SELECT t1.ID, t1.WAREHOUSE_OUT_NO, t1.WAREHOUSE_OUT_TITLE, t1.WAREHOUSE_ID, t1.WAREHOUSE_NAME, t1.STATUS, t1.REMARKS, t1.AUDIT_REMARK, t1.ACCEPTANCE_PERSON_ID, t1.ACCEPTANCE_PERSON_NAME, t1.ACCEPTANCE_TIME, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_MAT_WAREHOUSE_OUT_APP t1 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = t1.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
DEL_FLAG = 0
AND WAREHOUSE_OUT_NO LIKE #{warehouseOutNoPattern}
AND WAREHOUSE_OUT_TITLE LIKE #{warehouseOutTitlePattern}
AND WAREHOUSE_ID = #{warehouseId}
AND STATUS = #{status}
ORDER BY CREATE_TIME DESC

mapper.update:
UPDATE E_MAT_WAREHOUSE_OUT_APP
SET DEL_FLAG = 1,
    DELETE_BY = #{loginUserId,jdbcType=NUMERIC},
    DELETE_BY_NAME = #{loginUserName,jdbcType=VARCHAR},
    DELETE_TIME = #{now,jdbcType=TIMESTAMP}
WHERE ID = #{id}

mapper.select:
SELECT COUNT(*)
FROM E_MAT_WAREHOUSE_OUT_APP
WHERE WAREHOUSE_OUT_NO = #{warehouseOutNo}
AND DEL_FLAG = 0

    AND ID != #{id}

SELECT A.ID AS APPLICATION_ID, A.WAREHOUSE_OUT_NO, A.WAREHOUSE_OUT_TITLE, A.WAREHOUSE_ID, A.WAREHOUSE_NAME, A.STATUS, A.REMARKS, A.AUDIT_REMARK, A.ACCEPTANCE_PERSON_ID, A.ACCEPTANCE_PERSON_NAME, A.ACCEPTANCE_TIME, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, AD.ID AS DETAIL_ID, AD.WAREHOUSE_OUT_APP_ID AS DETAIL_OUT_APPLICATION_ID, AD.MATERIAL_ID AS DETAIL_MATERIAL_ID, AD.MATERIAL_NAME AS DETAIL_MATERIAL_NAME, AD.SPECIFICATION_MODEL AS DETAIL_SPECIFICATION_MODEL, AD.UNIT_CODE AS DETAIL_UNIT_CODE, AD.UNIT_NAME AS DETAIL_UNIT_NAME, AD.BRAND AS DETAIL_BRAND, AD.APPLICATION_QUANTITY AS DETAIL_APPLICATION_QUANTITY, AD.FLOW_DIRECTION AS DETAIL_FLOW_DIRECTION, AD.FLOW_TYPE AS DETAIL_FLOW_TYPE, AD.EQUIP_IDS AS DETAIL_EQUIP_IDS, AD.EQUIP_NAMES AS DETAIL_EQUIP_NAMES, NVL(AD.OUT_QUANTITY_SUM, 0) AS DETAIL_OUT_QUANTITY_SUM, NVL(STOCK.STOCK_QUANTITY, 0) AS DETAIL_STOCK_QUANTITY, AD.CREATE_BY AS DETAIL_CREATE_BY, AD.CREATE_BY_NAME AS DETAIL_CREATE_BY_NAME, AD.CREATE_TIME AS DETAIL_CREATE_TIME, AD.UPDATE_BY AS DETAIL_UPDATE_BY, AD.UPDATE_BY_NAME AS DETAIL_UPDATE_BY_NAME, AD.UPDATE_TIME AS DETAIL_UPDATE_TIME FROM E_MAT_WAREHOUSE_OUT_APP A LEFT JOIN E_MAT_WAREHOUSE_OUT_APP_DETAIL AD ON A.ID = AD.WAREHOUSE_OUT_APP_ID AND AD.DEL_FLAG = 0 AND (AD.OUT_QUANTITY_SUM IS NULL OR AD.OUT_QUANTITY_SUM < AD.APPLICATION_QUANTITY) LEFT JOIN ( SELECT WID.MATERIAL_ID, NVL(SUM(WID.REMAINING_QUANTITY), 0) AS STOCK_QUANTITY FROM E_MATERIAL_WAREHOUSE_IN_DETAIL WID INNER JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID WHERE WI.WAREHOUSE_ID = #{warehouseId} AND WI.ACCEPTANCE_STATUS = 1 GROUP BY WID.MATERIAL_ID ) STOCK ON AD.MATERIAL_ID = STOCK.MATERIAL_ID LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = A.ID
A.DEL_FLAG = 0 AND EXISTS ( SELECT 1 FROM E_MAT_WAREHOUSE_OUT_APP_DETAIL AD_CHECK WHERE AD_CHECK.WAREHOUSE_OUT_APP_ID = A.ID AND AD_CHECK.DEL_FLAG = 0 AND (AD_CHECK.OUT_QUANTITY_SUM IS NULL OR AD_CHECK.OUT_QUANTITY_SUM < AD_CHECK.APPLICATION_QUANTITY) )
AND A.WAREHOUSE_OUT_NO LIKE #{warehouseOutNoPattern}
AND A.WAREHOUSE_OUT_TITLE LIKE #{warehouseOutTitlePattern}
AND A.WAREHOUSE_ID = #{warehouseId}
and t3.INSTANCE_STATUS = #{status}
AND A.CREATE_BY = #{createBy}
ORDER BY A.CREATE_TIME DESC, AD.CREATE_TIME ASC
